//! # bench-early-exit — speed-vs-quality curve for LOSSY layer early-exit.
//!
//! Loads a local GGUF, prefills a prompt (token IDs), and greedily generates
//! `M` tokens to measure the speed/quality trade of the LOSSY early-exit gates
//! against a full-depth baseline. Two lossy modes are swept:
//!
//!   * SATURATION (primary): exit at the first layer `l >= min_layer` whose
//!     relative residual delta `‖h_{l-1}−h_{l-2}‖/‖h_{l-1}‖ < ε`. CHEAP — an
//!     O(hidden_dim) norm, no lm_head probe — so it is checked at every layer.
//!     ε is the flip-rate knob (larger ε ⇒ earlier exit ⇒ faster, lower agree).
//!   * MARGIN θ: candidate-layer lm_head probe, admit on the free `γ ≥ θ` test.
//!
//! METHODOLOGY (fixes the prior cold-cache 1.47× artifact):
//!   * WARM UP: one untimed generation pass before any timed measurement, so
//!     weight caches are warm for BOTH baseline and every sweep point.
//!   * Generate ≥64 tokens so per-token variance doesn't dwarf the signal.
//!   * Report MEAN PER-TOKEN FORWARD time (sum of forward_one profile total_us
//!     over the timed tokens), not just wall-clock, so caching can't confound.
//!   * COST MODEL first: per-layer µs and lm_head µs (lm_head_us/per_layer_us)
//!     on the loaded knot — tells us how many layers a saturation exit must skip
//!     to net-win (saturation probe ≈ free, so any net layers skipped = win).
//!
//! For each grid point: speedup× (mean per-token), argmax-agreement vs
//! full-depth (quality), mean exit depth (layers run / total). The KNEE is the
//! max speedup whose agreement ≥ 98% (≤2% flips); the ≥99% row is also flagged.
//!
//! Usage:
//!   bench-early-exit --knot PATH [--prompt-tokens 1,2,3] [--gen 80] [--warmup 8]
//!                    [--eps 0.02,0.04,0.06,0.08,0.12] [--theta 8,12,16,20]
//!                    [--min-layer N] [--layers 20,24,28] [--q 0.99]

use distributed_inference::early_exit::EarlyExitConfig;
use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;
use std::time::Instant;

fn arg_value(flag: &str) -> Option<String> {
    let mut args = std::env::args().skip(1);
    while let Some(a) = args.next() {
        if a == flag {
            return args.next();
        }
    }
    None
}

fn arg_usize(flag: &str, default: usize) -> usize {
    arg_value(flag)
        .and_then(|v| v.parse::<usize>().ok())
        .unwrap_or(default)
}

fn arg_f64(flag: &str, default: f64) -> f64 {
    arg_value(flag)
        .and_then(|v| v.parse::<f64>().ok())
        .filter(|v| v.is_finite())
        .unwrap_or(default)
}

fn parse_u32_list(raw: Option<String>) -> Vec<u32> {
    raw.unwrap_or_default()
        .split(',')
        .filter_map(|p| p.trim().parse::<u32>().ok())
        .collect()
}

fn parse_usize_list(raw: Option<String>) -> Vec<usize> {
    raw.unwrap_or_default()
        .split(',')
        .filter_map(|p| p.trim().parse::<usize>().ok())
        .collect()
}

fn parse_f64_list(raw: Option<String>) -> Vec<f64> {
    raw.unwrap_or_default()
        .split(',')
        .filter_map(|p| p.trim().parse::<f64>().ok())
        .filter(|v| v.is_finite())
        .collect()
}

fn argmax(logits: &[f32]) -> u32 {
    let mut best = 0usize;
    let mut best_val = f32::NEG_INFINITY;
    for (i, &v) in logits.iter().enumerate() {
        if v > best_val {
            best = i;
            best_val = v;
        }
    }
    best as u32
}

/// One generation run. Returns:
///   tokens (timed positions only), sum of forward_one total_us over timed
///   tokens, layers run over timed tokens, layers possible, wall-clock secs.
///
/// `reset_context_and_kv` zeroes KV so a layer-skipped run reads deterministic
/// zeros at skipped positions, never the previous run's leftover K/V.
struct RunOut {
    tokens: Vec<u32>,
    sum_total_us: u64,
    layers_run: u64,
    layers_possible: u64,
    secs: f64,
}

fn run_generate(
    pipe: &mut NativeLlamaPipeline,
    prompt: &[u32],
    gen: usize,
    warmup: usize,
) -> Result<RunOut, String> {
    pipe.reset_context_and_kv();
    let num_layers = pipe.num_layers() as u64;

    let mut pos = 0usize;
    for &tok in prompt {
        pipe.forward_one(tok as usize, pos, false)
            .map_err(|e| format!("prefill pos={pos}: {e}"))?;
        pos += 1;
    }
    let mut next = argmax(pipe.get_logits());

    let mut tokens = Vec::with_capacity(gen);
    let mut sum_total_us = 0u64;
    let mut layers_run = 0u64;
    let mut layers_possible = 0u64;

    // Warmup steps (not timed, not counted) — generated INSIDE this run so the
    // KV/weight caches are warm at the same positions the timed window reads.
    for _ in 0..warmup.min(gen) {
        pipe.forward_one(next as usize, pos, false)
            .map_err(|e| format!("warmup gen pos={pos}: {e}"))?;
        pos += 1;
        next = argmax(pipe.get_logits());
    }

    let timed = gen.saturating_sub(warmup);
    let t0 = Instant::now();
    for _ in 0..timed {
        tokens.push(next);
        pipe.forward_one(next as usize, pos, false)
            .map_err(|e| format!("gen pos={pos}: {e}"))?;
        sum_total_us += pipe.last_forward_profile().total_us;
        layers_run += pipe.last_exit_depth() as u64;
        layers_possible += num_layers;
        pos += 1;
        next = argmax(pipe.get_logits());
    }
    let secs = t0.elapsed().as_secs_f64();
    Ok(RunOut {
        tokens,
        sum_total_us,
        layers_run,
        layers_possible,
        secs,
    })
}

/// A single sweep row.
struct Row {
    label: String,
    mean_us: f64,
    speedup: f64,
    agreement: f64,
    depth_frac: f64,
}

fn agreement_pct(base: &[u32], other: &[u32]) -> (f64, usize, usize) {
    let n = base.len().min(other.len());
    let agree = base
        .iter()
        .zip(other.iter())
        .filter(|(a, b)| a == b)
        .count();
    let pct = if n > 0 {
        100.0 * agree as f64 / n as f64
    } else {
        0.0
    };
    (pct, agree, n)
}

fn main() -> Result<(), String> {
    let knot_path = arg_value("--knot").ok_or_else(|| {
        "usage: bench-early-exit --knot PATH [--prompt-tokens ..] [--gen 80] \
         [--warmup 8] [--eps ..] [--theta ..] [--min-layer N] [--layers ..] [--q 0.99]"
            .to_string()
    })?;
    let gen = arg_usize("--gen", 80);
    let warmup = arg_usize("--warmup", 8);
    let q = arg_f64("--q", 0.99);
    let layers_override = parse_usize_list(arg_value("--layers"));
    let min_layer_override = arg_value("--min-layer").and_then(|v| v.parse::<usize>().ok());
    let mut eps_grid = parse_f64_list(arg_value("--eps"));
    if eps_grid.is_empty() {
        eps_grid = vec![0.015, 0.03, 0.05, 0.08, 0.12, 0.18];
    }
    let mut theta_grid = parse_f64_list(arg_value("--theta"));
    if theta_grid.is_empty() {
        theta_grid = vec![6.0, 10.0, 14.0, 20.0];
    }
    let mut prompt = parse_u32_list(arg_value("--prompt-tokens"));
    if prompt.is_empty() {
        prompt = vec![1, 450, 6996, 310, 3444, 338, 263, 4234, 297, 4092];
    }

    eprintln!(
        "[bench] knot={knot_path} gen={gen} warmup={warmup} prompt_len={} \
         eps={eps_grid:?} theta={theta_grid:?}",
        prompt.len()
    );

    // ---- Load once. ----
    let load_t = Instant::now();
    let knot = KnotWeights::load(&knot_path).map_err(|e| format!("knot load: {e:?}"))?;
    // resonance_threshold = 1.0 DISABLES the stateful FFN resonance cache. That
    // cache persists across `reset_context_and_kv` (which only clears pos+KV),
    // so leaving it on (e.g. 0.8) makes consecutive runs nondeterministic and
    // corrupts the agreement metric. A clean speed/quality measurement needs a
    // deterministic forward pass.
    let mut pipe = NativeLlamaPipeline::from_knot(knot, false, 1.0);
    let num_layers = pipe.num_layers();
    let hidden_dim = pipe.hidden_dim();
    eprintln!(
        "[bench] loaded in {:.1}s  num_layers={num_layers}  hidden_dim={hidden_dim}",
        load_t.elapsed().as_secs_f64()
    );
    let min_layer = min_layer_override.unwrap_or(num_layers / 2);

    // ---- Candidate layers (for the margin gate). ----
    let candidates = if !layers_override.is_empty() {
        let mut v: Vec<usize> = layers_override
            .into_iter()
            .filter(|&k| k >= 1 && k < num_layers)
            .collect();
        v.sort_unstable();
        v.dedup();
        v
    } else {
        EarlyExitConfig::candidates_from_env(num_layers)
    };
    eprintln!("[bench] candidate exit layers (margin gate): {candidates:?}  (of {num_layers})");

    let mut ee_cfg = EarlyExitConfig {
        candidate_layers: candidates.clone(),
        calibrations: Vec::new(),
        q,
    };
    ee_cfg.q = q;
    pipe.set_early_exit_config(ee_cfg);

    // ---- PROFILE-ONLY: dump the per-layer saturation curve and exit. This
    //      skips calibration + the full sweep so the SATURATION SIGNAL can be
    //      read on a slow model (e.g. 8B CPU) within a time budget. Run with
    //      GNOSIS_EARLY_EXIT_DEBUG=1 to see the [ee-sat] per-layer rel deltas.
    if std::env::args().any(|a| a == "--profile-only") {
        let nprobe = arg_usize("--gen", 4);
        std::env::set_var("GNOSIS_EARLY_EXIT", "1");
        // Tiny positive ε keeps saturation_active TRUE (so the snapshot + debug
        // run every layer) while min_layer == num_layers guarantees no exit.
        std::env::set_var("GNOSIS_EARLY_EXIT_EPSILON", "0.0000001");
        std::env::set_var("GNOSIS_EARLY_EXIT_MIN_LAYER", num_layers.to_string());
        pipe.reset_context_and_kv();
        let mut pos = 0usize;
        for &tok in &prompt {
            pipe.forward_one(tok as usize, pos, false)
                .map_err(|e| format!("profile prefill: {e}"))?;
            pos += 1;
        }
        let mut next = argmax(pipe.get_logits());
        for t in 0..nprobe {
            eprintln!("[ee-sat] --- token {t} ---");
            pipe.forward_one(next as usize, pos, false)
                .map_err(|e| format!("profile gen: {e}"))?;
            pos += 1;
            next = argmax(pipe.get_logits());
        }
        std::env::remove_var("GNOSIS_EARLY_EXIT");
        std::env::remove_var("GNOSIS_EARLY_EXIT_EPSILON");
        std::env::remove_var("GNOSIS_EARLY_EXIT_MIN_LAYER");
        // Cost model from the last full-depth forward profile.
        let prof = pipe.last_forward_profile();
        let lm = prof.logit_us as f64;
        let per_layer = if num_layers > 0 {
            (prof.total_us.saturating_sub(prof.logit_us)) as f64 / num_layers as f64
        } else {
            0.0
        };
        let ratio = if per_layer > 0.0 { lm / per_layer } else { 0.0 };
        println!(
            "[cost-model] total={} µs/tok  per_layer={per_layer:.0} µs  \
             lm_head={lm:.0} µs  lm/layer={ratio:.2}×",
            prof.total_us
        );
        return Ok(());
    }

    // Calibrate the conformal/margin path (margin gate reuses the candidate
    // probe machinery, which requires a calibrated config to be "active").
    pipe.reset_context();
    pipe.calibrate_early_exit(&prompt, 0)
        .map_err(|e| format!("calibration: {e}"))?;

    // ---- WARM UP weight caches with one full untimed generation. ----
    std::env::remove_var("GNOSIS_EARLY_EXIT");
    let warm = run_generate(&mut pipe, &prompt, gen, warmup)?;

    // ---- DETERMINISM SELF-CHECK: two flag-OFF baselines must agree ~100%.
    //      If not, some stateful cache is leaking across runs and the agreement
    //      metric is meaningless — fail loudly rather than report noise.
    let det = run_generate(&mut pipe, &prompt, gen, warmup)?;
    let (det_pct, _, _) = agreement_pct(&warm.tokens, &det.tokens);
    eprintln!("[bench] determinism self-check (baseline vs baseline): {det_pct:.1}%");
    if det_pct < 99.9 {
        return Err(format!(
            "NON-DETERMINISTIC forward pass: two flag-OFF baselines agree only \
             {det_pct:.1}% — a stateful cache is leaking across runs; \
             agreement numbers would be invalid. Aborting."
        ));
    }

    // ---- COST MODEL: full-depth per-layer µs and lm_head µs. ----
    // Re-run baseline (warm) and read the averaged profile.
    let base = run_generate(&mut pipe, &prompt, gen, warmup)?;
    let timed = base.tokens.len();
    let base_mean_us = if timed > 0 {
        base.sum_total_us as f64 / timed as f64
    } else {
        0.0
    };
    // Probe a single full-depth forward to split total/lm_head.
    let prof = pipe.last_forward_profile();
    let lm_head_us = prof.logit_us as f64;
    let per_layer_us = if num_layers > 0 {
        (prof.total_us.saturating_sub(prof.logit_us)) as f64 / num_layers as f64
    } else {
        0.0
    };
    let lm_over_layer = if per_layer_us > 0.0 {
        lm_head_us / per_layer_us
    } else {
        0.0
    };

    println!("\n================ COST MODEL (warm, full depth) ================");
    println!("model:               {knot_path}");
    println!("num_layers:          {num_layers}   hidden_dim: {hidden_dim}");
    let base_wall_per_tok_ms = if timed > 0 {
        1000.0 * base.secs / timed as f64
    } else {
        0.0
    };
    println!(
        "mean per-token total: {base_mean_us:.0} µs   (baseline, {timed} timed tokens; \
         wall-clock {base_wall_per_tok_ms:.0} ms/tok cross-check)"
    );
    println!("per-layer µs:        {per_layer_us:.1}");
    println!("lm_head µs:          {lm_head_us:.1}");
    println!(
        "lm_head / per-layer: {lm_over_layer:.2}×   \
         (a margin probe must skip > this many layers to net-win; \
          a saturation probe is ~free so ANY net layers skipped = win)"
    );
    println!("min_exit_layer:      {min_layer}");
    println!("==============================================================\n");

    if base_mean_us <= 0.0 {
        return Err("baseline mean per-token us is zero".into());
    }

    // ---- SWEEP. Each point runs from an equally-warm state (cache already
    //      warmed above; reset_context_and_kv per run keeps KV deterministic).
    let mut sat_rows: Vec<Row> = Vec::new();
    std::env::set_var("GNOSIS_EARLY_EXIT", "1");
    std::env::set_var("GNOSIS_EARLY_EXIT_MIN_LAYER", min_layer.to_string());

    println!("================ SATURATION SWEEP (ε) ================");
    println!(
        "{:>8}  {:>10}  {:>9}  {:>10}  {:>10}",
        "ε", "mean µs", "speedup", "agree %", "depth %"
    );
    for &eps in &eps_grid {
        std::env::set_var("GNOSIS_EARLY_EXIT_EPSILON", format!("{eps}"));
        std::env::remove_var("GNOSIS_EARLY_EXIT_THETA");
        let out = run_generate(&mut pipe, &prompt, gen, warmup)?;
        std::env::remove_var("GNOSIS_EARLY_EXIT_EPSILON");
        let mean_us = out.sum_total_us as f64 / out.tokens.len().max(1) as f64;
        let speedup = base_mean_us / mean_us.max(1.0);
        let (agree, _, _) = agreement_pct(&base.tokens, &out.tokens);
        let depth_frac = if out.layers_possible > 0 {
            out.layers_run as f64 / out.layers_possible as f64
        } else {
            1.0
        };
        println!(
            "{:>8.3}  {:>10.0}  {:>8.3}×  {:>9.1}%  {:>9.1}%",
            eps,
            mean_us,
            speedup,
            agree,
            100.0 * depth_frac
        );
        sat_rows.push(Row {
            label: format!("ε={eps}"),
            mean_us,
            speedup,
            agreement: agree,
            depth_frac,
        });
    }
    std::env::remove_var("GNOSIS_EARLY_EXIT_EPSILON");
    println!("=====================================================\n");

    // ---- MARGIN θ sweep (for comparison). ----
    let mut margin_rows: Vec<Row> = Vec::new();
    println!("================ MARGIN SWEEP (θ) ================");
    println!(
        "{:>8}  {:>10}  {:>9}  {:>10}  {:>10}",
        "θ", "mean µs", "speedup", "agree %", "depth %"
    );
    for &theta in &theta_grid {
        std::env::set_var("GNOSIS_EARLY_EXIT_THETA", format!("{theta}"));
        std::env::remove_var("GNOSIS_EARLY_EXIT_EPSILON");
        let out = run_generate(&mut pipe, &prompt, gen, warmup)?;
        std::env::remove_var("GNOSIS_EARLY_EXIT_THETA");
        let mean_us = out.sum_total_us as f64 / out.tokens.len().max(1) as f64;
        let speedup = base_mean_us / mean_us.max(1.0);
        let (agree, _, _) = agreement_pct(&base.tokens, &out.tokens);
        let depth_frac = if out.layers_possible > 0 {
            out.layers_run as f64 / out.layers_possible as f64
        } else {
            1.0
        };
        println!(
            "{:>8.2}  {:>10.0}  {:>8.3}×  {:>9.1}%  {:>9.1}%",
            theta,
            mean_us,
            speedup,
            agree,
            100.0 * depth_frac
        );
        margin_rows.push(Row {
            label: format!("θ={theta}"),
            mean_us,
            speedup,
            agreement: agree,
            depth_frac,
        });
    }
    std::env::remove_var("GNOSIS_EARLY_EXIT");
    std::env::remove_var("GNOSIS_EARLY_EXIT_MIN_LAYER");
    println!("=================================================\n");

    // ---- KNEE: max speedup with agreement ≥ 98% (≤2% flips); also ≥99%. ----
    let knee = |rows: &[Row], thresh: f64| -> Option<(String, f64, f64, f64, f64)> {
        rows.iter()
            .filter(|r| r.agreement >= thresh)
            .max_by(|a, b| a.speedup.partial_cmp(&b.speedup).unwrap())
            .map(|r| (r.label.clone(), r.speedup, r.agreement, r.depth_frac, r.mean_us))
    };

    println!("================ VERDICT ================");
    let report_knee = |name: &str, rows: &[Row]| {
        match knee(rows, 98.0) {
            Some((lab, sp, ag, df, mu)) => println!(
                "{name}: KNEE (≥98% agree)  {lab}  → {sp:.3}× speedup, \
                 {ag:.1}% agree, {:.1}% layers run, {mu:.0} µs/tok",
                100.0 * df
            ),
            None => println!("{name}: no point reaches ≥98% agreement"),
        }
        match knee(rows, 99.0) {
            Some((lab, sp, ag, df, mu)) => println!(
                "{name}: ≥99% agree     {lab}  → {sp:.3}× speedup, \
                 {ag:.1}% agree, {:.1}% layers run, {mu:.0} µs/tok",
                100.0 * df
            ),
            None => println!("{name}: no point reaches ≥99% agreement"),
        }
    };
    report_knee("SATURATION", &sat_rows);
    report_knee("MARGIN", &margin_rows);
    println!("========================================");

    Ok(())
}
